 61→/* Tell the app that we no longer want to focus the WebView and should instead return keyboard
 62→ * focus to a native answer input method.
 63→ * Naming subject to change.
 64→ */
 65→function _relinquishFocus() {
 66→    // Clicking on a hint set the Android mouse cursor to a text entry bar, even after navigating
 67→    // away. This fixes the issue.
 68→    document.body.style.cursor = "default";
 69→    window.location.href = "signal:relinquishFocus";
 70→}
