109→/* Look at the text entered into the input box and send the text on a return */
110→function taKey(itag, e) {
111→    var keycode;
112→    if (window.event) {
113→        keycode = window.event.keyCode;
114→    } else if (e) {
115→        keycode = e.which;
116→    } else {
117→        return true;
118→    }
119→
120→    if (keycode == 13) {
121→        //#5944 - percent wasn't encoded, but Mandarin was.
122→        var encodedVal = encodeURI(itag.value);
123→        window.location.href = "typeentertext:" + encodedVal;
124→        return false;
125→    } else {
126→        return true;
127→    }
128→}
