190→/* Add function 2 hook to function 1.
191→ * Function 2 should be `(arg: Object) => void`;  `arg` will be an Object returned from `JSON.parse`
192→ */
193→function addHook(fn1, fn2) {
194→    if (fn1 === "ankiSearchCard") {
195→        searchCardHook.push(fn2);
196→    }
197→    if (fn1 === "ankiSttResult") {
198→        speechToTextHook.push(fn2);
199→    }
200→}
201→
202→let searchCardHook = [];
203→function ankiSearchCard(result) {
204→    if (!searchCardHook) {
205→        return;
206→    }
207→
208→    result = JSON.parse(result);
209→    for (var i = 0; i < searchCardHook.length; i++) {
210→        searchCardHook[i](result);
211→    }
212→}
213→
214→// hook for getting speech to text result in callback method
215→let speechToTextHook = [];
216→function ankiSttResult(result) {
217→    if (!speechToTextHook) {
218→        return;
219→    }
220→    result = JSON.parse(result);
221→    result.value = JSON.parse(result.value);
222→    for (var i = 0; i < speechToTextHook.length; i++) {
223→        speechToTextHook[i](result);
224→    }
225→}
