227→function showHint() {
228→    var hints = document.querySelectorAll("a.hint");
229→    for (var i = 0; i < hints.length; i++) {
230→        if (hints[i].style.display != "none") {
231→            hints[i].click();
232→            break;
233→        }
234→    }
235→}
236→
237→function showAllHints() {
238→    document.querySelectorAll("a.hint").forEach(el => {
239→        el.click();
240→    });
241→}
